using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Shipment>(e =>
        {
            e.HasIndex(s => s.TrackingNumber).IsUnique();
            e.HasIndex(s => s.CustomerEmail);
        });

        builder.Entity<Shipment>().HasData(
            new Shipment { Id = 1, TrackingNumber = "TRK-001234", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, ShippedDate = new DateTime(2026, 5, 20), EstimatedDelivery = new DateTime(2026, 5, 27), RecipientName = "Alice Johnson", CustomerEmail = "alice@example.com" },
            new Shipment { Id = 2, TrackingNumber = "TRK-001235", Origin = "Chicago, IL", Destination = "Miami, FL", Status = ShipmentStatus.OutForDelivery, ShippedDate = new DateTime(2026, 5, 18), EstimatedDelivery = new DateTime(2026, 5, 25), RecipientName = "Bob Smith", CustomerEmail = "bob@example.com" },
            new Shipment { Id = 3, TrackingNumber = "TRK-001236", Origin = "Seattle, WA", Destination = "Denver, CO", Status = ShipmentStatus.Delivered, ShippedDate = new DateTime(2026, 5, 15), EstimatedDelivery = new DateTime(2026, 5, 22), RecipientName = "Carol White", CustomerEmail = "carol@example.com" },
            new Shipment { Id = 4, TrackingNumber = "TRK-001237", Origin = "Dallas, TX", Destination = "Boston, MA", Status = ShipmentStatus.Pending, ShippedDate = new DateTime(2026, 5, 24), EstimatedDelivery = new DateTime(2026, 5, 31), RecipientName = "Dave Brown", CustomerEmail = "alice@example.com" },
            new Shipment { Id = 5, TrackingNumber = "TRK-001238", Origin = "San Francisco, CA", Destination = "Phoenix, AZ", Status = ShipmentStatus.Delayed, ShippedDate = new DateTime(2026, 5, 19), EstimatedDelivery = new DateTime(2026, 5, 28), RecipientName = "Eve Davis", CustomerEmail = "bob@example.com" }
        );
    }
}

